import logging
from logging.handlers import RotatingFileHandler
import os

# set up logging to file
logging.basicConfig(level=logging.DEBUG,
                    format='%(asctime)s %(levelname)-8s %(message)s',
                    datefmt='%Y-%m-%d %H:%M:%S',
                    filename='/path/to/your/logfile.log', # set your log file path here
                    filemode='a+') 

# define a Handler which writes INFO messages or higher to the sys.stderr
console = logging.StreamHandler()
console.setLevel(logging.INFO)

# set a format which is simpler for console use
formatter = logging.Formatter('%(name)-12s: %(levelname)-8s %(message)s')

# tell the handler to use this format
console.setFormatter(formatter)

# add the handler to the root logger
logging.getLogger().addHandler(console)

# Rotate log file after reaching 5MB and keep backup of last 3 files
handler = RotatingFileHandler('/path/to/your/logfile.log', maxBytes=5*1024*1024, backupCount=3)
logging.getLogger().addHandler(handler)

# set file permission to read and write for owner
os.chmod("/path/to/your/logfile.log", 0o664)